var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"피, 피오네 언니. 다른 단원분들이 침식체로 변했어요…!","JPN":"フィ、フィオネさん。他の団員の方々も、侵食体に変わってしまいました……！","ENG":"F-Fione! The other knights, they've turned into C.O.s...!","TWN":"菲，菲，菲奧尼姊姊。其他隊員們變成了侵蝕體……！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"전부 본부에 남아 계시던 분들이에요! 여기서 대체 무슨 일이 있었던 거지?","JPN":"みんな本部に残っていた人たちです！　いったいここで何が……！？","ENG":"They were all stationed at HQ! What on earth happened here?","TWN":"全都是留在總部的人！這裡到底發生了什麼事？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"침착하세요! 침식사태의 영향일지도 모르는 이상 저들을 바깥으로 향하게 해선 안 됩니다!","JPN":"落ち着いてください！　侵食事態の影響かもしれません。彼らを外へ出してはだめです！","ENG":"Stay calm! If this is part of the Corruption disaster, we absolutely cannot let them escape outside!","TWN":"冷靜點！既然可能是侵蝕事態的影響，就不能讓他們向外面移動！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"우선 진형을 갖춰, 저들을 가두는데 주력하세요!","JPN":"まずは陣形を整えて、彼らを封じ込めることを優先してください！","ENG":"Form up! Our top priority is to trap and contain them!","TWN":"首先佈置陣型，專注於將他們困住！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NPC_NULL","text":{"KOREA":"당-처엄!","JPN":"あ～たり！","ENG":"Bingo!","TWN":"當——初見！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"크윽!?","JPN":"くっ！？","ENG":"Kgh?!","TWN":"呃？！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"잠깐 대화한 걸로 네크로맨시를 파악하다니~. 넌 나랑 다르게 머리가 좋구나?","JPN":"ちょっと会話しただけでネクロマンシーに気づくなんて～、君はアタシと違って賢いんだね！","ENG":"You figured out it was necromancy after just a short chat? You're way smarter than me!","TWN":"僅僅通過短暫的對話就能理解死靈術～你和我不一樣，腦子真好使啊？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"나는 바보라 <color=#ffd34c>지팡이</color>로 되살리고도 제대로 죽였는지 확신이 안 섰거든~.","JPN":"アタシはバカだから、<color=#ffd34c>杖</color>で蘇らせても、ちゃんと殺せてるか確信が持てなかったんだよね～","ENG":"I'm dumb, so even after reviving them with the <color=#ffd34c>Staff</color>, I couldn't tell if I'd really killed them or not!","TWN":"我這個笨蛋用<color=#ffd34c>復活之杖</color>復活後，也不確定是否真的殺死了～"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"그래서, 또 죽였다? 다시 되살리니까 그제서야 죽인 걸 알았어!","JPN":"だからまた殺したの！　もう一回蘇らせて、やっと殺せたってわかった！","ENG":"So I killed them again! Only when they revived again did I realize they were actually dead!","TWN":"所以，又殺了它？復活之後才知道殺了它！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"그러니까아~? 머리 좋은 네가, 여기서 제일 강한 녀석이야!","JPN":"だから～、頭のいい君が、ここで一番強いやつ！","ENG":"That's why! You're the strongest one here! Because you're smart!","TWN":"所以說~？聰明的你，就是這裡最強的傢伙！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"부단장님!!","JPN":"副団長！！","ENG":"Deputy!!","TWN":"副部長！！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐야, 대체! 왜 쓰러트려도 계속 일어나는 건데?","JPN":"どうしてなの！　どうして倒しても立ち上がるの？","ENG":"What?! Why do they keep getting back up even after we beat them?!","TWN":"怎麼回事，究竟！為什麼打倒了還會繼續站起來？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"부탁이니까… 이제 그만 좀 일어나라고!","JPN":"お願いだから……もう立ち上がってこないで！","ENG":"Come on... Please just stay down already!","TWN":"拜託了……現在請不要再起來了！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"정석과는 거리가 먼 변칙적인 공격. 그럼에도 기사단의 기예가 담겨있다.","JPN":"型破りで異質な攻撃……だが、そこには確かに騎士団の技がある。","ENG":"Unorthodox attacks with no regard for form. But still infused with knightly technique.","TWN":"與常規相去甚遠的變異攻擊。即便如此，仍蘊含著騎士團的技藝。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"익숙하지만 낯선, 이 느낌은…….","JPN":"見慣れているようで、どこか違和感のあるこの感覚……","ENG":"This feeling, it's familiar yet unfamiliar...","TWN":"熟悉卻陌生，這種感覺……"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"네 녀석. 설마…!!","JPN":"貴様は、まさか……！！","ENG":"You... You're...!","TWN":"你這傢伙。莫非…！！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"맞아~. 나 레드시프트!","JPN":"正解～。アタシ、レッドシフト！","ENG":"Yup! I'm with Red Shift!","TWN":"沒錯～我是紅移！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"게 자리의 아셀라 프로… 프로… 뭐였더라?","JPN":"蟹座のアセッラ・プロ……プロ……なんだっけ？","ENG":"Cancer Knight, Ascella Pro– Pro... What was the rest again?","TWN":"巨蟹座的亞瑟拉·普羅…普羅…是什麼來著？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"아무튼~. 너희들 적이야!","JPN":"とにかく～、君たちの敵！","ENG":"Anyway, I'm your enemy!","TWN":"總之～你們是敵人！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"그런데, 이상하네? 원래 파랑이들은 이렇게 약한가?","JPN":"でもおかしいな？　青服ってこんなに弱いの？","ENG":"But hey, this is weird. Are Blueys usually this weak?","TWN":"不過，奇怪呢？原來藍色的傢伙們這麼弱嗎？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"아니면 부족한가~? 제대로 싸우려면 뭔가 느낌이 와야 해?","JPN":"それとも、足りない～？　何かビビッと来ないと、本気出せない？","ENG":"Or are you just not enough? I need to feel something if I'm gonna enjoy the fight!","TWN":"不然是不夠嗎～？要好好戰鬥的話，總得有點感覺吧?"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"어디 보자…….","JPN":"どれどれ……","ENG":"Let's see...","TWN":"讓我看看……"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};